function fmtMoney(val) {
    if (!val && val !== 0) return '';
    return '$ ' + Math.round(val).toLocaleString('es-AR');
}
function imgToBase64(file) {
    return new Promise((res, rej) => {
        const r = new FileReader();
        r.onload = e => res(e.target.result);
        r.onerror = rej;
        r.readAsDataURL(file);
    });
}

// ── Obtener datos actuales del sistema ──
function _getDatosActuales() {
    // Leer presupuesto actual (puede estar en window.presupuesto o en el carrito)
    let items = [];
    if (window.presupuesto && window.presupuesto.length > 0) {
        items = window.presupuesto;
    } else {
        // Intentar leer del DOM si el carrito está renderizado
        const listaEl = document.getElementById('listaPresupuesto');
        if (listaEl) {
            // Los datos ya están en window.presupuesto, si está vacío el carrito está vacío
        }
    }
    
    // Cliente
    const cliente = document.getElementById('clienteNombre')?.value?.trim() 
        || document.getElementById('inputCliente')?.value?.trim() 
        || 'Sin especificar';
    
    // Total
    const totalEl = document.getElementById('labelTotalPresupuesto');
    const total = parseFloat(document.getElementById('precioTotal')?.value) 
        || parseFloat(totalEl?.innerText?.replace(/[^0-9]/g, '')) 
        || 0;

    return { items, cliente, total };
}

// ══════════════════════════════════════════════════════════════
// GENERAR HTML PRESUPUESTO
// ══════════════════════════════════════════════════════════════
window.generarDocPresupuesto = async function(p) {
    const items = p.items || [];
    const cliente = p.cliente || 'Sin especificar';
    const numPpto = String(p.id || 1001).padStart(4, '0');
    const fecha = new Date().toLocaleDateString('es-AR', {day:'2-digit',month:'2-digit',year:'numeric'});
    const mostrarPrecios = p.mostrarPrecios !== false;
    const descuento = parseFloat(p.descuento) || 0;
    const metodoPago = p.metodoPago || '';
    const validez = p.validez || '10 días';
    const entrega = p.entrega || 'A convenir';
    const nota = p.nota || '';
    const imagenes = p.imagenes || [];

    const total = items.reduce((acc, it) => acc + (parseFloat(it.costo) || 0), 0);
    const descMonto = total * (descuento / 100);
    const totalFinal = total - descMonto;

    const itemsHTML = items.length > 0 ? items.map((it, i) => `
        <tr>
            <td class="td-num">${String(i+1).padStart(2,'0')}</td>
            <td class="td-desc">
                <strong>${it.nombre || it.textoOpciones || 'Ítem'}</strong>
                ${it.otDetalle ? `<small>${it.otDetalle}</small>` : ''}
            </td>
            <td class="td-precio">
                ${mostrarPrecios && it.costo ? fmtMoney(it.costo) : (mostrarPrecios ? '<span style="color:#ccc">—</span>' : '')}
            </td>
        </tr>
    `).join('') : `<tr><td colspan="3" style="padding:20px 6px;color:#aaa;text-align:center;font-style:italic;">Sin ítems cargados</td></tr>`;

    const refsHTML = imagenes.length > 0 ? `
        <div class="doc-referencias">
            <div class="sec-titulo">Referencias visuales del trabajo</div>
            <div class="referencias-grid">
                ${imagenes.map(src => `<img src="${src}" alt="Ref">`).join('')}
            </div>
        </div>
    ` : '';

    return `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><title>Presupuesto #${numPpto}</title>
<style>${GECKO_PRINT_STYLES}</style></head>
<body>
<div class="page">
  <div class="page-content">
    <div class="doc-header">
        <div class="header-logo"><img src="${GECKO_LOGO_B64}" alt="Gecko"></div>
        <div class="header-contacto">
            <span>✉ ${GECKO_BRAND.mail}</span>
            <span>◎ ${GECKO_BRAND.instagram}</span>
            <span>● ${GECKO_BRAND.whatsapp}</span>
            <span>⊕ ${GECKO_BRAND.web}</span>
        </div>
        <div class="header-tipo">
            <div class="tipo-label">Presupuesto</div>
            <div class="tipo-numero">#${numPpto} · ${fecha}</div>
        </div>
    </div>
    <div class="doc-meta">
        <div class="meta-item"><label>Cliente</label><value>${cliente}</value></div>
        <div class="meta-item"><label>Válido por</label><value>${validez}</value></div>
        <div class="meta-item"><label>Entrega estimada</label><value>${entrega}</value></div>
    </div>
    <div class="doc-items">
        <table class="items-table">
            <thead><tr>
                <th style="width:26px">#</th>
                <th>Descripción del trabajo</th>
                <th class="th-r">${mostrarPrecios ? 'Precio' : ''}</th>
            </tr></thead>
            <tbody>${itemsHTML}</tbody>
        </table>
    </div>
    ${refsHTML}
    <div class="doc-totales">
        <div class="totales-box">
            ${mostrarPrecios ? `<div class="totales-row"><span class="lbl">Subtotal</span><span class="val">${fmtMoney(total)}</span></div>` : ''}
            ${descuento > 0 ? `<div class="totales-row"><span class="lbl">Dto. ${descuento}% ${metodoPago ? `(${metodoPago})` : ''}</span><span class="val" style="color:#e53e3e">- ${fmtMoney(descMonto)}</span></div>` : ''}
            <div class="totales-row final"><span class="lbl">TOTAL FINAL</span><span class="val">${fmtMoney(totalFinal)}</span></div>
        </div>
    </div>
    <div class="doc-condiciones">
        <div class="cond-item"><label>Condiciones de pago</label><p>Adelanto del 60% del valor.<br>Resto, contra entrega.</p></div>
        <div class="cond-item"><label>Condición IVA</label><p>No incluye IVA · Monotributo.<br>Emitimos Factura C.</p></div>
        ${nota ? `<div class="cond-item" style="grid-column:1/-1"><label>Notas adicionales</label><p>${nota}</p></div>` : ''}
    </div>
  </div>
  <div class="doc-footer">
    <span>✉ ${GECKO_BRAND.mail}</span><span class="sep">|</span>
    <span>◎ ${GECKO_BRAND.instagram}</span><span class="sep">|</span>
    <span>⊕ ${GECKO_BRAND.web}</span>
  </div>
</div>
<script>window.onload=()=>{window.print();window.onafterprint=()=>window.close();}<\/script>
</body></html>`;
};

